// Parse PWA FormData into workflow format
// PWA sends: Business Card Image (file), Business Card Back Side (Optional) (file),
// Voice Note (file), Sales Person Name, Remark, Event Name, Quick Notes

const inputItem = $input.first();
const json = inputItem.json;
const body = json.body || json;
const binary = inputItem.binary || {};
const items = [];

// Extract form fields from PWA (check both json.body and json root)
const sales_person_name = body['Sales Person Name'] || json['Sales Person Name'] || json.salesPerson || '';
const remark = body['Remark'] || json['Remark'] || json.remark || '';
const event_name = body['Event Name'] || json['Event Name'] || json.eventName || '';
const quick_notes = body['Quick Notes'] || json['Quick Notes'] || json.quickNotes || '';
const send_notification = body['Send Notification'] || json['Send Notification'] || 'Yes';

// Find images and voice note from binary data
const frontImages = {};
const backImages = {};
let voiceNote = null;
let frontIdx = 0;
let backIdx = 0;

for (const key of Object.keys(binary)) {
  const k = key.toLowerCase();
  if (k.includes('business_card_image') || k.includes('business card image') || (k.includes('front') && !k.includes('back'))) {
    frontImages[String(frontIdx)] = binary[key];
    frontIdx++;
  } else if (k.includes('back') || k.includes('business_card_back')) {
    backImages[String(backIdx)] = binary[key];
    backIdx++;
  } else if (k.includes('voice') || k.includes('audio')) {
    voiceNote = binary[key];
  }
}

// If no categorized images found, try generic binary keys
if (frontIdx === 0) {
  for (const key of Object.keys(binary)) {
    if (!key.toLowerCase().includes('voice') && !key.toLowerCase().includes('audio')) {
      frontImages[String(frontIdx)] = binary[key];
      frontIdx++;
    }
  }
}

for (const index of Object.keys(frontImages)) {
  const item = {
    json: {
      sales_person_name: sales_person_name,
      remark: remark,
      event_name: event_name,
      quick_notes: quick_notes,
      has_voice_note: voiceNote ? true : false,
      send_notification: send_notification
    },
    binary: {
      Business_Card_Image: frontImages[index]
    }
  };
  if (backImages[index]) {
    item.binary.Business_Card_Back_Side = backImages[index];
  }
  if (voiceNote && index === '0') {
    item.binary.Voice_Note = voiceNote;
  }
  items.push(item);
}

if (items.length === 0) {
  return [{ json: { sales_person_name, remark, event_name, quick_notes, has_voice_note: false, send_notification }, binary }];
}

return items;

// Split multiple card uploads into individual items
// Also handle voice notes and extra form fields

const inputItem = $input.first();
const json = inputItem.json;
const binary = inputItem.binary || {};
const items = [];

// Extract form fields
const sales_person_name = json['Sales Person Name'] || '';
const remark = json.Remark || '';
const event_name = json['Event Name'] || '';
const quick_notes = json['Quick Notes'] || '';

// Separate front images, back images, and voice notes
const frontImages = {};
const backImages = {};
let voiceNote = null;

for (const key of Object.keys(binary)) {
  if (key.startsWith('Business_Card_Image_')) {
    const index = key.replace('Business_Card_Image_', '');
    frontImages[index] = binary[key];
  } else if (key.startsWith('Business_Card_Back_Side_Optional_')) {
    const index = key.replace('Business_Card_Back_Side_Optional_', '');
    backImages[index] = binary[key];
  } else if (key.startsWith('Voice_Note_Optional_') || key.startsWith('Voice_Note_')) {
    voiceNote = binary[key];
  }
}

// Process each front image and match with corresponding back image
for (const index of Object.keys(frontImages)) {
  const item = {
    json: {
      sales_person_name: sales_person_name,
      remark: remark,
      event_name: event_name,
      quick_notes: quick_notes,
      has_voice_note: voiceNote ? true : false
    },
    binary: {
      Business_Card_Image: frontImages[index]
    }
  };

  // Add back side image if exists for this index
  if (backImages[index]) {
    item.binary.Business_Card_Back_Side = backImages[index];
  }

  // Add voice note to first card item only
  if (voiceNote && index === Object.keys(frontImages)[0]) {
    item.binary.Voice_Note = voiceNote;
  }

  items.push(item);
}

if (items.length === 0) {
  return [inputItem];
}

return items;

// Convert binary image to base64 and build OpenAI Vision API request
const item = $input.first();
const json = item.json;

// Binary data is lost after Set nodes — fetch from the source node directly
let binary = item.binary || {};
if (!binary.Business_Card_Image) {
  try {
    const pwaNode = $('Parse PWA Data').first();
    if (pwaNode && pwaNode.binary && pwaNode.binary.Business_Card_Image) {
      binary = pwaNode.binary;
    }
  } catch(e) {}
}
if (!binary.Business_Card_Image) {
  try {
    const splitNode = $('Split Cards & Extract Voice').first();
    if (splitNode && splitNode.binary && splitNode.binary.Business_Card_Image) {
      binary = splitNode.binary;
    }
  } catch(e) {}
}

const imageData = binary.Business_Card_Image;
const backData = binary.Business_Card_Back_Side;

const toDataUrl = (imgData) => {
  if (!imgData || !imgData.data) return null;
  let mime = (imgData.mimeType || 'image/jpeg').toLowerCase();
  if (mime === 'image/jpg') mime = 'image/jpeg';
  if (mime === 'image/heic' || mime === 'image/heif') mime = 'image/jpeg';
  if (!['image/png', 'image/jpeg', 'image/gif', 'image/webp'].includes(mime)) mime = 'image/jpeg';
  let data = imgData.data;
  if (typeof data === 'string') {
    if (data.startsWith('data:')) data = data.split(',').slice(1).join(',');
    data = data.replace(/[\s\r\n]/g, '');
  } else if (Buffer.isBuffer(data)) {
    data = data.toString('base64');
  }
  return { url: `data:${mime};base64,${data}`, mime, len: data.length };
};

const frontResult = toDataUrl(imageData);
const backResult = toDataUrl(backData);

const frontUrl = frontResult ? frontResult.url : null;
const backUrl = backResult ? backResult.url : null;
const debugMime = frontResult ? frontResult.mime : 'none';
const debugLen = frontResult ? frontResult.len : 0;

// Build content array with images
const userContent = [
  {
    type: 'text',
    text: 'Extract all contact information from this business card image. Return ONLY valid JSON with the specified fields. Read EXACTLY what is printed on the card — do NOT invent or guess any data.'
  }
];

if (frontUrl) {
  userContent.push({ type: 'image_url', image_url: { url: frontUrl, detail: 'high' } });
}
if (backUrl) {
  userContent.push({ type: 'image_url', image_url: { url: backUrl, detail: 'high' } });
}

const systemPrompt = `You are a business card OCR expert. Extract ALL information EXACTLY as printed on the card image. Do NOT make up, guess, or hallucinate any data.

Extract these fields:
1. company_name: Company/business name only
2. full_name: Person full name
3. job_title: Job title/designation/position
4. phone_number: Landline/office/direct phone number
5. mobile_number: Mobile/cell phone number(s)
6. email: Email address
7. website: Website URL
8. address: Complete physical address
9. products: Products, services, or items the company sells/manufactures
10. other_details: GSTIN, certifications, taglines, social handles, establishment year, etc.

CRITICAL RULES:
- Read ONLY what is ACTUALLY printed on the card image
- Do NOT generate example or placeholder data
- If a field is not visible on the card, return null for that field
- Return ONLY valid JSON, no markdown, no extra text`;

const requestBody = {
  model: 'gpt-4o',
  max_tokens: 1000,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: frontUrl ? userContent : 'No image provided. Return empty JSON with all null fields.' }
  ]
};

return [{
  json: {
    sales_person_name: json.sales_person_name || '',
    remark: json.remark || '',
    event_name: json.event_name || '',
    quick_notes: json.quick_notes || '',
    has_voice_note: json.has_voice_note || false,
    send_notification: json.send_notification || 'Yes',
    _vision_request: requestBody,
    _vision_request_body: JSON.stringify(requestBody),
    _debug_mime: debugMime,
    _debug_data_len: debugLen,
    _debug_has_image: !!frontUrl
  }
}];

// Parse OpenAI Vision API response and extract card data
const items = $input.all();
const results = [];

for (const item of items) {
  const apiResponse = item.json;

  // Check for API-level errors
  if (apiResponse.error) {
    throw new Error('OpenAI API Error: ' + (apiResponse.error.message || JSON.stringify(apiResponse.error)));
  }

  // Extract text content from OpenAI response
  const content = apiResponse.choices?.[0]?.message?.content || '';

  if (!content) {
    throw new Error('OpenAI returned empty response. API response: ' + JSON.stringify(apiResponse).substring(0, 500));
  }

  // Parse JSON from content (handle markdown code blocks)
  let extracted = {};
  try {
    const cleaned = content
      .replace(/```json\n?/gi, '')
      .replace(/```\n?/g, '')
      .trim();
    extracted = JSON.parse(cleaned);
  } catch (e) {
    // Try to extract first JSON object from text
    const match = content.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        extracted = JSON.parse(match[0]);
      } catch (e2) {
        extracted = {};
      }
    }
  }

  // Get form data from upstream Prepare Vision Request node
  let formData = {
    sales_person_name: '',
    remark: '',
    event_name: '',
    quick_notes: '',
    has_voice_note: false,
    send_notification: 'Yes'
  };

  try {
    const upstream = $('Prepare Vision Request').first().json;
    formData.sales_person_name = upstream.sales_person_name || '';
    formData.remark = upstream.remark || '';
    formData.event_name = upstream.event_name || '';
    formData.quick_notes = upstream.quick_notes || '';
    formData.has_voice_note = upstream.has_voice_note || false;
    formData.send_notification = upstream.send_notification || 'Yes';
  } catch (e) {
    try {
      const pwaData = $('Parse PWA Data').first().json;
      formData.sales_person_name = pwaData.sales_person_name || '';
      formData.remark = pwaData.remark || '';
      formData.event_name = pwaData.event_name || '';
      formData.quick_notes = pwaData.quick_notes || '';
      formData.has_voice_note = pwaData.has_voice_note || false;
      formData.send_notification = pwaData.send_notification || 'Yes';
    } catch (e2) {}
  }

  results.push({
    json: {
      output: {
        company_name: extracted.company_name || null,
        full_name: extracted.full_name || null,
        job_title: extracted.job_title || null,
        phone_number: extracted.phone_number || null,
        mobile_number: extracted.mobile_number || null,
        email: extracted.email || null,
        website: extracted.website || null,
        address: extracted.address || null,
        products: extracted.products || null,
        other_details: extracted.other_details || null
      },
      sales_person_name: formData.sales_person_name,
      remark: formData.remark,
      event_name: formData.event_name,
      quick_notes: formData.quick_notes,
      has_voice_note: formData.has_voice_note,
      send_notification: formData.send_notification
    }
  });
}

return results;

// Process extracted card data + voice note transcription
const items = $input.all();
const processedItems = [];

// Function to clean phone numbers
const cleanNumbers = (val) => {
  if (!val) return '';
  return String(val)
    .replace(/[^0-9,+\s-]/g, '')
    .replace(/\+91/g, '')
    .replace(/[\s-]/g, '')
    .replace(/,+/g, ',')
    .split(',')
    .map(n => n.trim())
    .filter(n => n.length >= 5 && n.length <= 15)
    .join(', ');
};

for (const item of items) {
  const output = item.json.output || item.json;

  if (output.phone_number) {
    output.phone_number = cleanNumbers(output.phone_number);
  }
  if (output.mobile_number) {
    output.mobile_number = cleanNumbers(output.mobile_number);
  }

  // Get voice note transcription
  let voice_note_text = '';
  try {
    const voiceNode = $('Transcribe Voice Note');
    if (voiceNode && voiceNode.first()) {
      voice_note_text = voiceNode.first().json.text || voiceNode.first().json.transcription || '';
    }
  } catch (e) {}

  // Get form data from upstream
  let sales_person_name = '', remark = '', event_name = '', quick_notes = '', send_notification = 'Yes';

  // First try from the item itself (Parse Vision Output carries these)
  if (item.json.sales_person_name !== undefined) {
    sales_person_name = item.json.sales_person_name || '';
    remark = item.json.remark || '';
    event_name = item.json.event_name || '';
    quick_notes = item.json.quick_notes || '';
    send_notification = item.json.send_notification || 'Yes';
  } else {
    try {
      // Try PWA Webhook path first (Parse PWA Data)
      const pwaData = $('Parse PWA Data').first().json;
      sales_person_name = pwaData.sales_person_name || '';
      remark = pwaData.remark || '';
      event_name = pwaData.event_name || '';
      quick_notes = pwaData.quick_notes || '';
    } catch (e) {
      try {
        // Fallback to Form trigger path (Split Cards & Extract Voice)
        const formData = $('Split Cards & Extract Voice').first().json;
        sales_person_name = formData.sales_person_name || '';
        remark = formData.remark || '';
        event_name = formData.event_name || '';
        quick_notes = formData.quick_notes || '';
        send_notification = formData.send_notification || 'Yes';
      } catch (e2) {}
    }
  }

  const record = {
    company_name: output.company_name || '',
    full_name: output.full_name || '',
    job_title: output.job_title || '',
    phone_number: output.phone_number || '',
    mobile_number: output.mobile_number || '',
    email: output.email || '',
    website: output.website || '',
    address: output.address || '',
    products: output.products || '',
    other_details: output.other_details || '',
    sales_person_name: sales_person_name,
    remark: remark,
    event_name: event_name,
    quick_notes: quick_notes,
    voice_note: voice_note_text,
    send_notification: send_notification
  };

  processedItems.push({ json: record });
}

return processedItems;

function cleanPhone(num) {
    if (!num) return "";
    let cleaned = String(num).replace(/[^0-9]/g, "");
    if (!cleaned || cleaned.length < 5) return "";
    if (cleaned.startsWith("0")) cleaned = cleaned.substring(1);
    if (cleaned.length === 10) cleaned = "91" + cleaned;
    else if (!cleaned.startsWith("91") || cleaned.length < 12) cleaned = "91" + cleaned.slice(-10);
    return cleaned.substring(0, 12);
}

const d = $input.item.json;
const phone = cleanPhone(d["Phone Number"] || d.phone_number || "");
const mobile = cleanPhone(d["Mobile Number"] || d.mobile_number || "");
const email = d["Email Address"] || d.email || "";
let sendNotif = d["Send Notification"] || d.send_notification;
if (!sendNotif) {
    try { sendNotif = $("Process & Clean Data").first().json.send_notification; } catch(e) {}
}
sendNotif = sendNotif || "Yes";

return {
    phone_number: phone,
    mobile_number: mobile,
    email: email,
    send_notification: sendNotif,
    name: d["Name"] || d.name || "",
    company: d["Company Name"] || d.company_name || "",
    event_name: d["Event"] || d["Event Name"] || d.event_name || "IMTEX 2026 Bangalore",
    sales_person: d["Sales Person Name"] || d.sales_person_name || ""
};

